def get_available_tegs():
    """Get list of available TEGs from data."""
    try:
        df = read_file('data/all-scores.parquet')
        tegs = sorted(df['TEGNum'].unique())
        return tegs
    except Exception as e:
        st.error(f"Error loading TEG list: {e}")
        return []

