def _add_series_markers(fig, size=3, border_width=1):
    for tr in fig.data:
        if getattr(tr, "type", None) == "scatter":
            # outline uses the line colour for the trace
            line_col = getattr(tr, "line", {}).get("color", None) if isinstance(tr.line, dict) else tr.line.color
            tr.mode = "lines+markers" if (tr.mode is None or "markers" not in tr.mode) else tr.mode
            tr.marker = dict(
                symbol="circle",
                size=size,
                color="white",                          # fill
                line=dict(width=border_width, color=line_col)  # outline
            )
    return fig

def format_value(value: Any, value_type: str) -> str:
    """Formats values based on their type.

    Args:
        value (Any): The value to format.
        value_type (str): The type of the value ('GrossVP', 'NetVP', or
            'Stableford').

    Returns:
        str: The formatted value as a string.
    """
    try:
        num = float(value)
        if value_type in ['GrossVP', 'NetVP']:
            # Format vs par values with +/- signs
            if num > 0:
                return f"+{int(num)}" if num.is_integer() else f"+{num}"
            elif num < 0:
                return f"{int(num)}" if num.is_integer() else f"{num}"
            else:
                return "="
        elif value_type == 'Stableford':
            return f"{int(round(num))}"
        else:
            return str(value)
    except (ValueError, TypeError):
        return str(value)

def add_round_annotations(fig, max_round):
    for round_num in range(1, max_round + 1):
        x_pos = (round_num - 1) * 18
        fig.add_vline(x=x_pos, line=dict(color='lightgrey', width=1))
        fig.add_annotation(x=x_pos + 9, y=0.08, text=f'R{round_num}', 
                           showarrow=False, yref='paper', yshift=-40)

def format_value(value, chart_type):
    if chart_type == 'stableford':
        return f"{value:.0f}"
    elif chart_type == 'gross':
        if value > 0:
            return f"+{value:.0f}"
        elif value < 0:
            return f"{value:.0f}"
        else:
            return "="
    elif chart_type == 'ranking':
        # Format ranking as ordinal (1st, 2nd, 3rd, etc.)
        rank = int(value)
        if rank == 1:
            return "1st"
        elif rank == 2:
            return "2nd"
        elif rank == 3:
            return "3rd"
        else:
            return f"{rank}th"
    else:
        return f"{value:.0f}"

def get_section_layouts() -> dict:
    """Calculates the optimal column layout for each section.

    This function determines the number of columns to use for displaying pages
    within each section, based on the number of pages in that section.

    Returns:
        dict: A dictionary mapping each section to its optimal number of
        columns.
    """
    section_counts = {}
    for page_info in PAGE_DEFINITIONS.values():
        section = page_info["section"]
        section_counts[section] = section_counts.get(section, 0) + 1

    # Calculate optimal columns (max 4, min 2)
    layouts = {}
    for section, count in section_counts.items():
        if count <= 2:
            layouts[section] = 2
        elif count <= 4:
            layouts[section] = count
        else:
            layouts[section] = 4
    return layouts

def fmt(val):
        if pd.isna(val):
            return "-"                 # display only; data stays NaN
        s = str(val)
