def compute_overall_trend(_df: pd.DataFrame) -> pd.DataFrame:
    x = _df["SI_num"].astype(float).values
    y = _df["GrossVP"].astype(float).values
    if len(x) < 2:
        # fallback: flat line at overall mean if not enough points
        a, b = 0.0, float(np.nanmean(y) if len(y) else 0.0)
    else:
        a, b = np.polyfit(x, y, 1)
    xs = np.arange(1, 19, dtype=float)
    yhat = a * xs + b
    return pd.DataFrame({"SI": xs.astype(int), "yhat": yhat})

def load_data() -> pd.DataFrame:
    df = load_all_data()

    # Ensure required fields exist
    required = set([VALUE_FIELD]) | set(FILTER_FIELDS)
    missing = required - set(df.columns)
    if missing:
        raise ValueError(f"Missing required columns: {sorted(missing)}")

    df = df.copy()

    # TEGNum numeric for ordering
    if "TEGNum" in df.columns:
        df["TEGNum"] = pd.to_numeric(df["TEGNum"], errors="coerce").astype("Int64")

    # Round as string for display
    if "Round" in df.columns:
        df["Round"] = df["Round"].astype(str)

    # Strings
    for col in ["Course", "Area", "Player"]:
        if col in df.columns:
            df[col] = df[col].astype(str)

    # Value numeric
    df[VALUE_FIELD] = pd.to_numeric(df[VALUE_FIELD], errors="coerce")

    # Potential X fields numeric
    for xf in X_FIELD_CHOICES:
        if xf in df.columns:
            df[xf] = pd.to_numeric(df[xf], errors="coerce")

    return df

def make_row_label(row: pd.Series, dims: list[str]) -> str:
    if not dims:
        return "All"
    parts = []
    for d in dims:
        val = row[d]
        if d == "TEGNum" and pd.notna(val):
            val = str(int(val))
        else:
            val = str(val)
        if d == "Course" and val.startswith("PGA Catalunya - "):
            val = val.replace("PGA Catalunya - ", "")
        parts.append(val)
    return " | ".join(parts)

def pretty_sel(field: str, sels: list[str]) -> str:
