def create_batch_request(
    custom_id: str,
    model: str,
    max_tokens: int,
    system_prompt: str,
    user_message: str,
    use_cache: bool = True
) -> Dict[str, Any]:
    """
    Create a single batch request in the format required by Anthropic Batch API.

    Args:
        custom_id: Unique identifier for this request (e.g., "TEG17_R1_story_notes")
        model: Model name (e.g., "claude-sonnet-4-5")
        max_tokens: Maximum tokens for response
        system_prompt: System prompt text
        user_message: User message text
        use_cache: Whether to use prompt caching (default True)

    Returns:
        Dict in format required by Batch API
    """
    system_block = {
        "type": "text",
        "text": system_prompt
    }

    if use_cache:
        system_block["cache_control"] = {"type": "ephemeral"}

    return {
        "custom_id": custom_id,
        "params": {
            "model": model,
            "max_tokens": max_tokens,
            "system": [system_block],
            "messages": [{
                "role": "user",
                "content": user_message
            }]
        }
    }

