def parse_range(range_str):
    """
    Parse a range string like '1-4' or a single number '3'.

    Args:
        range_str: String like '1-4' or '3'

    Returns:
        List of integers
    """
    if '-' in range_str:
        start, end = range_str.split('-')
        return list(range(int(start), int(end) + 1))
    else:
        return [int(range_str)]

