def format_vs_par_value(value):
        """Format vs-par values with appropriate +/- symbols."""
        if pd.isna(value):
            return ""
        if value > 0:
            return f"+{value:.2f}"
        elif value < 0:
            return f"{value:.2f}"
        else:
            return "="
